mapper.select:
SELECT (SELECT COUNT(*) FROM pi_targets t WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
) AS totalTargets,
COUNT(f.hash_id) AS totalDetections,
SUM(CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN 1 ELSE 0 END) AS totalProcessed,
SUM(CASE WHEN dp.processing_flag IS NULL OR dp.processing_flag = 0 THEN 1 ELSE 0 END) AS totalUnprocessed,
SUM(CASE WHEN dp.approval_status = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount,
SUM(CASE WHEN dp.approval_status = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount,
(SELECT MAX(sh.regdate) FROM pi_scan_history sh INNER JOIN pi_targets t2 ON sh.target_id = t2.target_id AND sh.ap_no = t2.ap_no WHERE t2.TARGET_USE = 'Y'
AND t2.group_id = #{groupId}
) AS lastScanDate
FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND f.regdate >= #{startDate}
AND f.regdate <= #{endDate}

SELECT s.data_type AS datatype, dt.datatype_label AS datatypeLabel, SUM(s.match_count) AS count, SUM(CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN s.match_count ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.approval_status = 'Y' THEN s.match_count ELSE 0 END) AS truePositiveCount FROM pi_summary s INNER JOIN pi_targets t ON s.target_id = t.target_id AND s.ap_no = t.ap_no LEFT JOIN pi_datatypes dt ON s.data_type = dt.datatype_id LEFT JOIN pi_data_processing dp ON s.target_id = dp.target_id AND s.ap_no = dp.ap_no AND s.object_id = dp.hash_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
GROUP BY s.data_type, dt.datatype_label ORDER BY count DESC

SELECT f.path AS path, COUNT(*) AS detectionCount, SUM(CASE WHEN dp.approval_status = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, t.name AS targetName FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
GROUP BY f.path, t.name ORDER BY detectionCount DESC LIMIT 20

SELECT f.hash_id AS findNo, f.path AS findPath, s.data_type AS datatype, f.regdate AS findDate, CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN 'Y' ELSE 'N' END AS processYn, CASE WHEN dp.approval_status = 'Y' THEN 'Y' WHEN dp.approval_status = 'N' THEN 'N' ELSE NULL END AS trueYn, t.name AS targetName, a.agent_connected_ip AS targetIp FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_summary s ON f.target_id = s.target_id AND f.ap_no = s.ap_no AND f.hash_id = s.object_id LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id LEFT JOIN pi_agents a ON t.TARGET_ID = a.agent_name AND t.ap_no = a.ap_no WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
ORDER BY f.regdate DESC
LIMIT #{limit}

SELECT IFNULL(dt.datatype_label, s.data_type) AS label, SUM(s.match_count) AS value FROM pi_summary s INNER JOIN pi_targets t ON s.target_id = t.target_id AND s.ap_no = t.ap_no LEFT JOIN pi_datatypes dt ON s.data_type = dt.datatype_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND s.regdate >= #{startDate}
AND s.regdate <= #{endDate}
GROUP BY s.data_type, dt.datatype_label ORDER BY value DESC

SELECT DATE_FORMAT(f.regdate, '%Y-%m') AS label, COUNT(*) AS totalCount, SUM(CASE WHEN dp.approval_status = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.approval_status = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN 1 ELSE 0 END) AS processedCount FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND f.regdate >= #{startDate}
AND f.regdate <= #{endDate}
GROUP BY DATE_FORMAT(f.regdate, '%Y-%m') ORDER BY label ASC

SELECT t.target_id AS targetNo, t.name AS targetName, a.agent_connected_ip AS targetIp, t.group_id AS groupId, tg.name AS groupName, COUNT(f.hash_id) AS detectionCount, SUM(CASE WHEN dp.approval_status = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id LEFT JOIN pi_agents a ON t.TARGET_ID = a.agent_name AND t.ap_no = a.ap_no LEFT JOIN pi_target_group tg ON t.group_idx = tg.idx WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
GROUP BY t.target_id, t.ap_no, t.name, a.agent_connected_ip, t.group_id, tg.name ORDER BY detectionCount DESC
LIMIT #{limit}
